#!/bin/bash
# Universal Thrum agent startup script
# Auto-generated by thrum init
set -e

# Bind Thrum to this checkout even if the agent later cds into another worktree.
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DEFAULT_THRUM_HOME="$(cd "$SCRIPT_DIR/.." && pwd)"
export THRUM_HOME="${THRUM_HOME:-$DEFAULT_THRUM_HOME}"

# --- Listener heartbeat mode ---
# Usage: thrum-startup.sh --listener-heartbeat
# Verifies listener PID file exists (thrum wait manages the actual PID file).
# Requires THRUM_NAME and THRUM_AGENT_ID to be set (from CLAUDE_ENV_FILE).
if [ "$1" = "--listener-heartbeat" ]; then
  AGENT_ID="${THRUM_AGENT_ID:-${THRUM_NAME:-}}"
  if [ -z "$AGENT_ID" ]; then
    AGENT_ID=$(thrum --repo "$THRUM_HOME" whoami --field agent_id 2>/dev/null || true)
  fi
  if [ -z "$AGENT_ID" ]; then
    echo "Error: Could not determine agent ID" >&2
    exit 1
  fi

  PID_FILE="${THRUM_HOME:-.}/.thrum/var/${AGENT_ID}-listener.pid"
  if [ -f "$PID_FILE" ]; then
    echo "Listener PID file exists ($(jq -r '.pid // "?"' "$PID_FILE" 2>/dev/null))"
  else
    echo "No PID file — thrum wait will create one"
  fi
  exit 0
fi

# 1. Ensure daemon is running
if ! thrum --repo "$THRUM_HOME" daemon status &>/dev/null; then
  thrum --repo "$THRUM_HOME" daemon start
fi

# 2. Read existing identity from thrum whoami (--field avoids a jq dependency)
AGENT_NAME=$(thrum --repo "$THRUM_HOME" whoami --field agent_id 2>/dev/null || true)
AGENT_ROLE=$(thrum --repo "$THRUM_HOME" whoami --field role 2>/dev/null || true)
AGENT_MODULE=$(thrum --repo "$THRUM_HOME" whoami --field module 2>/dev/null || true)
AGENT_INTENT=$(thrum --repo "$THRUM_HOME" whoami --field intent 2>/dev/null || true)

# If whoami returned nothing, thrum is not initialized in this worktree.
# Allow env var overrides, but don't silently fall back to hardcoded defaults.
if [ -z "$AGENT_NAME" ]; then
  AGENT_NAME="${THRUM_NAME:-}"
  AGENT_ROLE="${THRUM_ROLE:-}"
  AGENT_MODULE="${THRUM_MODULE:-}"
  AGENT_INTENT="${THRUM_INTENT:-}"

  if [ -z "$AGENT_NAME" ]; then
    echo "⚠ Thrum is not initialized in this worktree ($(pwd))."
    echo "  No identity found via 'thrum whoami' and no THRUM_NAME env var set."
    echo "  Run: thrum quickstart --name <name> --role <role> --module <module> --intent <intent>"
    exit 1
  fi
else
  # Allow env vars to override whoami values
  AGENT_NAME="${THRUM_NAME:-$AGENT_NAME}"
  AGENT_ROLE="${THRUM_ROLE:-$AGENT_ROLE}"
  AGENT_MODULE="${THRUM_MODULE:-$AGENT_MODULE}"
  AGENT_INTENT="${THRUM_INTENT:-$AGENT_INTENT}"
fi

export THRUM_NAME="$AGENT_NAME"
export THRUM_AGENT_ID="${THRUM_AGENT_ID:-$AGENT_NAME}"
export THRUM_ROLE="$AGENT_ROLE"
export THRUM_MODULE="$AGENT_MODULE"
export THRUM_INTENT="$AGENT_INTENT"

# Persist env vars into Claude Code's session environment.
# CLAUDE_ENV_FILE is provided by SessionStart hooks — vars written here survive
# into subsequent Bash tool calls. Without this, exports die with the subprocess.
if [ -n "$CLAUDE_ENV_FILE" ]; then
  cat >> "$CLAUDE_ENV_FILE" <<ENVEOF
export THRUM_HOME="$THRUM_HOME"
export THRUM_NAME="$THRUM_NAME"
export THRUM_AGENT_ID="$THRUM_AGENT_ID"
export THRUM_ROLE="$THRUM_ROLE"
export THRUM_MODULE="$THRUM_MODULE"
export THRUM_INTENT="$THRUM_INTENT"
ENVEOF
fi

# 3. Register agent (reuses existing identity)
thrum --repo "$THRUM_HOME" quickstart \
  --name "$AGENT_NAME" \
  --role "$AGENT_ROLE" \
  --module "$AGENT_MODULE" \
  --intent "$AGENT_INTENT" \
  --json

# 4. Check inbox and output context
thrum --repo "$THRUM_HOME" inbox --unread --json

# 5. Optional: Announce presence
if [ "${THRUM_ANNOUNCE:-false}" = "true" ]; then
  thrum --repo "$THRUM_HOME" send "Agent $AGENT_NAME online" --to @everyone --json
fi

# 6. Emit CronCreate instruction. The runtime (Claude Code) consumes the
# instruction block from our stdout via the SessionStart hook's context-
# injection path and schedules the 15-minute inbox-check cron. For
# runtimes without that capability (e.g. cli-only), this is a no-op at
# the agent's end — the command still prints, but nothing reads it.
thrum --repo "$THRUM_HOME" cron install-inbox-poll 2>/dev/null || true
